    cin.tie(0);

    cout.tie(0);



    int n, m;

    set<int> s;

    cin >> n >> m;

    vii v(n);

    range(i, 1, m)s.insert(i);

    for (auto &p : v)cin >> p.fr >> p.sc;

    sort(ALL(v), [](const pii &a, const pii &b) {

        return a.sc > b.sc || a.sc == b.sc && a.fr < b.fr;

    });





    ll ans = 0;

    for (auto p : v) {

        auto it = s.lower_bound(p.fr);

