    x = find(x);

    y = find(y);

    if (x == y) return;

    if (rank[x] < rank[y]) {

      par[y] += par[x];

      par[x] = -y;

    } else {

      par[x] += par[y];

      par[y] = -x;

      if (rank[x] == rank[y]) rank[x]++;

    }

  }

  bool isSame(ll x, ll y) {

    return find(x) == find(y);

  }

};



